const https = require('https');
const url = require('url');

function httpReq(method, fullUrl, data) {
  return new Promise((resolve, reject) => {
    const parsed = url.parse(fullUrl);
    const opts = {
      hostname: parsed.hostname,
      port: parsed.port || 443,
      path: parsed.path,
      method,
      headers: { 'Content-Type': 'application/json' }
    };
    if (data && data.headers) {
      Object.assign(opts.headers, data.headers);
    }
    const req = https.request(opts, (res) => {
      let body = '';
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(body)); } catch(e) { resolve(body); }
      });
    });
    req.on('error', reject);
    if (data && data.body) req.write(typeof data.body === 'string' ? data.body : JSON.stringify(data.body));
    req.end();
  });
}

const body = $input.first().json.body;
const text = (body.message?.text || body.text || '').trim();
const chat_id = body.message?.chat?.id || body.chat_id;

const SUPABASE_URL = 'https://fdabygmromuqtysitodp.supabase.co';
const SUPABASE_ANON_KEY = $env.SUPABASE_ANON_KEY;
const TELEGRAM_BOT_TOKEN = $env.TELEGRAM_BOT_TOKEN;

const supaHeaders = {
  'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
  'apikey': SUPABASE_ANON_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

async function supaGet(path) {
  return httpReq('GET', `${SUPABASE_URL}/rest/v1/${path}`, { headers: supaHeaders });
}

async function supaPost(path, postData) {
  return httpReq('POST', `${SUPABASE_URL}/rest/v1/${path}`, { headers: supaHeaders, body: postData });
}

async function supaPatch(path, patchData) {
  return httpReq('PATCH', `${SUPABASE_URL}/rest/v1/${path}`, { headers: supaHeaders, body: patchData });
}

async function sendTelegram(chatId, msg) {
  return httpReq('POST', `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`, {
    body: { chat_id: chatId, text: msg, parse_mode: 'Markdown' }
  });
}

let reply = 'Unknown command. Use /task, /tasks, /done, or /run.';

try {
  if (text.startsWith('/task ')) {
    const title = text.slice(6).trim();
    if (!title) {
      reply = 'Usage: /task <title>';
    } else {
      const rows = await supaPost('charlie_tasks', { title, type: 'task', status: 'pending' });
      const task = Array.isArray(rows) ? rows[0] : rows;
      reply = `Task created: *${task.title}*\nID: \`${task.id}\``;
    }

  } else if (text === '/tasks') {
    const rows = await supaGet('charlie_tasks?status=in.(pending,in_progress,queued)&order=created_at.asc');
    if (!rows || !rows.length) {
      reply = 'No pending or in-progress tasks.';
    } else {
      reply = rows.map((t) => {
        const icon = t.status === 'in_progress' ? '🔄' : t.status === 'queued' ? '🚀' : '⬜';
        return `${icon} *${t.title}*\n   \`${t.id.slice(0,8)}\` — ${t.status}`;
      }).join('\n\n');
    }

  } else if (text.startsWith('/done ')) {
    const search = text.slice(6).trim();
    if (!search) {
      reply = 'Usage: /done <id_prefix or title>';
    } else {
      let rows = await supaGet(`charlie_tasks?id=eq.${search}&status=neq.complete`);
      if (!rows || !rows.length) {
        const allTasks = await supaGet('charlie_tasks?status=neq.complete&order=created_at.desc');
        rows = (allTasks || []).filter(t => t.id.startsWith(search));
      }
      if (!rows.length) {
        rows = await supaGet(`charlie_tasks?title=ilike.*${encodeURIComponent(search)}*&status=neq.complete`);
      }
      if (!rows || !rows.length) {
        reply = `No matching task found for: ${search}`;
      } else if (rows.length > 1) {
        reply = `Multiple matches (${rows.length}). Be more specific:\n` + rows.map(t => `• \`${t.id.slice(0,8)}\` ${t.title}`).join('\n');
      } else {
        const task = rows[0];
        await supaPatch(`charlie_tasks?id=eq.${task.id}`, { status: 'complete', completed_at: new Date().toISOString() });
        reply = `Task completed: *${task.title}*`;
      }
    }

  } else if (text.startsWith('/run ')) {
    const search = text.slice(5).trim();
    if (!search) {
      reply = 'Usage: /run <id_prefix or title>';
    } else {
      let rows = await supaGet(`charlie_tasks?id=eq.${search}&status=neq.complete`);
      if (!rows || !rows.length) {
        const allTasks = await supaGet('charlie_tasks?status=neq.complete&order=created_at.desc');
        rows = (allTasks || []).filter(t => t.id.startsWith(search));
      }
      if (!rows.length) {
        rows = await supaGet(`charlie_tasks?title=ilike.*${encodeURIComponent(search)}*&status=neq.complete`);
      }
      if (!rows || !rows.length) {
        reply = `No matching task found for: ${search}`;
      } else if (rows.length > 1) {
        reply = `Multiple matches (${rows.length}). Be more specific:\n` + rows.map(t => `• \`${t.id.slice(0,8)}\` ${t.title}`).join('\n');
      } else {
        const task = rows[0];
        await supaPatch(`charlie_tasks?id=eq.${task.id}`, { status: 'queued' });
        reply = `Task queued for execution: *${task.title}*`;
      }
    }

  } else {
    reply = 'Commands:\n/task <title> — create task\n/tasks — list pending\n/done <id or title> — complete\n/run <id or title> — queue for execution';
  }
} catch (err) {
  reply = `Error: ${err.message}`;
}

if (chat_id) {
  await sendTelegram(chat_id, reply);
}

return [{ json: { reply, chat_id } }];

